from flask import Flask, request, jsonify, g
import logging

app = Flask(__name__)

# Configure logging
logging.basicConfig(filename='application.log', level=logging.INFO)

def log_login_attempt(username, password, email, ip_address, user_agent):
    log_message = f"Login Attempt: Username={username}, Password={password}, Email={email}, IP Address={ip_address}, User Agent={user_agent}"
    logging.info(log_message)

@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    email = data.get('email')

    ip_address = request.remote_addr
    user_agent = request.headers.get('User-Agent')

    # Dummy authentication logic
    if username == "admin" and password == "admin":
        log_login_attempt(username, password, email, ip_address, user_agent)
        return jsonify({"message": "Login successful"}), 200
    else:
        log_login_attempt(username, password, email, ip_address, user_agent)
        return jsonify({"message": "Invalid credentials"}), 401

if __name__ == '__main__':
    app.run(debug=True)